
-- SCRIPT DE INSERCIÓN DE USUAERIOS - RP DIGITAL (PostgreSQL)
SELECT 'Ricardo', 'Rip123', 'ADMIN', FALSE
WHERE NOT EXISTS (SELECT 1 FROM usuarios WHERE matricula = 'Ricardo');

SELECT 'Olga', 'oligator', 'VENDEDOR', FALSE
WHERE NOT EXISTS (SELECT 1 FROM usuarios WHERE matricula = 'Olga');

SELECT 'Alejandro', 'Alex123', 'VENDEDOR', FALSE
WHERE NOT EXISTS (SELECT 1 FROM usuarios WHERE matricula = 'Alejandro');


